import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Customer } from '../../core/models';

/**
 * Customers list + create/edit. The form is opened via `?modal=new` or
 * `?edit=:id` query params restored from ActivatedRoute. Mutations are gated to
 * the sales + admin roles. Mock data lives in a typed signal; service_agent
 * wires ApiService.listCustomers()/createCustomer()/updateCustomer().
 */
@Component({
  selector: 'app-customers',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './customers.component.html',
  styleUrl: './customers.component.css',
})
export class CustomersComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly saving = signal(false);

  readonly customers = signal<Customer[]>([
    { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example', phone: '+1 202 555 0180' },
    { id: 'c2', name: 'Contoso Ltd', email: 'ap@contoso.example', phone: '+1 415 555 0142' },
    { id: 'c3', name: 'Fabrikam Inc', email: 'buy@fabrikam.example', phone: null },
  ]);

  readonly canEdit = computed(() => this.auth.isSales());

  // Modal state, restored from query params.
  readonly modalOpen = signal(false);
  readonly editingId = signal<string | null>(null);
  form: Partial<Customer> = { name: '', email: '', phone: '' };

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    // service_agent: this.customers.set(await ApiService.listCustomers()).
    this.route.queryParams.subscribe((q) => {
      if (q['modal'] === 'new' && this.canEdit()) {
        this.openCreate();
      } else if (q['edit']) {
        this.openEdit(q['edit']);
      } else {
        this.modalOpen.set(false);
      }
    });
  }

  openCreate(): void {
    this.editingId.set(null);
    this.form = { name: '', email: '', phone: '' };
    this.modalOpen.set(true);
  }

  openEdit(id: string): void {
    const c = this.customers().find((x) => x.id === id);
    if (!c) return;
    this.editingId.set(id);
    this.form = { name: c.name, email: c.email, phone: c.phone ?? '' };
    this.modalOpen.set(true);
  }

  close(): void {
    this.router.navigate([], { queryParams: {} });
    this.modalOpen.set(false);
  }

  save(): void {
    if (!this.form.name || !this.form.email) {
      this.error.set('Name and email are required.');
      return;
    }
    this.saving.set(true);
    // service_agent: call createCustomer()/updateCustomer() then refresh.
    const id = this.editingId();
    if (id) {
      this.customers.update((list) =>
        list.map((c) => (c.id === id ? { ...c, ...this.form } as Customer : c)),
      );
    } else {
      this.customers.update((list) => [
        { id: 'c' + (list.length + 1), ...this.form } as Customer,
        ...list,
      ]);
    }
    this.saving.set(false);
    this.close();
  }

  remove(id: string, ev: Event): void {
    ev.stopPropagation();
    if (!this.canEdit()) return;
    this.customers.update((list) => list.filter((c) => c.id !== id));
  }
}
